"use client"

import { useEffect, useRef, useState, useCallback } from "react"
import { Trophy } from "lucide-react"

// ── 게임 상수 ──────────────────────────────────────────
const LOGICAL_WIDTH = 1920
const LOGICAL_HEIGHT = 1080
const PLAYER_X = 200
const PLAYER_WIDTH = 100
const PLAYER_HEIGHT = 100
const TRASH_WIDTH = 108
const TRASH_HEIGHT = 108
const HITBOX_PADDING = 20
const GRAVITY = 0.04
const JUMP = -3
const SCROLL_SPEED_BASE = 3
const SCROLL_SPEED_INCREMENT = 0.5
const MAX_SCROLL_SPEED = 10
const TRASH_FALL_SPEED_MIN = 1
const TRASH_FALL_SPEED_MAX = 3
const SPAWN_INTERVAL_BASE = 1000
const SPAWN_INTERVAL_MIN = 400
const SPAWN_REDUCTION = 50

// ── Base64 이미지 ────────────────────────────────────────
const IMG_FISH = "data:image/png;base64,"
const IMG_BG   = "data:image/png;base64,"
const IMG_TRASH: string[] = [
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,",
]

// ── 타입 ────────────────────────────────────────────────
interface TrashObject {
  x: number
  y: number
  fallSpeed: number
  type: number
  passed: boolean
}

interface GameState {
  playerY: number
  playerVelocity: number
  trashList: TrashObject[]
  score: number
  isGameOver: boolean
  bgScrollX: number
  currentBgDarkness: number
  lastSpawnTime: number
}

function makeInitialState(): GameState {
  return {
    playerY: LOGICAL_HEIGHT / 2,
    playerVelocity: 0,
    trashList: [],
    score: 0,
    isGameOver: false,
    bgScrollX: 0,
    currentBgDarkness: 0,
    lastSpawnTime: 0,
  }
}

// ── 컴포넌트 ─────────────────────────────────────────────
export function MiniGameSection() {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const containerRef = useRef<HTMLDivElement>(null)
  const stateRef = useRef<GameState>(makeInitialState())
  const imagesRef = useRef<{ fish: HTMLImageElement; bg: HTMLImageElement; trash: HTMLImageElement[] } | null>(null)
  const rafRef = useRef<number>(0)
  const startedRef = useRef(false)

  const [displayScore, setDisplayScore] = useState(0)
  const [highScore, setHighScore] = useState(0)
  const [phase, setPhase] = useState<"idle" | "playing" | "over">("idle")

  // ── 이미지 로드 (마운트 1회) ──────────────────────────
  useEffect(() => {
    const loadImg = (src: string) =>
      new Promise<HTMLImageElement>((res) => {
        const img = new Image()
        img.onload = () => res(img)
        img.onerror = () => res(img)
        img.src = src
      })

    Promise.all([
      loadImg(IMG_FISH),
      loadImg(IMG_BG),
      ...IMG_TRASH.map(loadImg),
    ]).then(([fish, bg, ...trash]) => {
      imagesRef.current = { fish, bg, trash }
    })
  }, [])

  // ── 캔버스 스케일 ─────────────────────────────────────
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    canvas.width = LOGICAL_WIDTH
    canvas.height = LOGICAL_HEIGHT
  }, [])

  // ── 그리기 ───────────────────────────────────────────
  const draw = useCallback(() => {
    const canvas = canvasRef.current
    const ctx = canvas?.getContext("2d")
    const imgs = imagesRef.current
    if (!canvas || !ctx) return

    const s = stateRef.current

    // 배경
    if (imgs && imgs.bg.complete && imgs.bg.naturalWidth !== 0) {
      const bgScale = LOGICAL_HEIGHT / imgs.bg.naturalHeight
      const bgW = imgs.bg.naturalWidth * bgScale
      ctx.drawImage(imgs.bg, s.bgScrollX, 0, bgW, LOGICAL_HEIGHT)
      let nx = s.bgScrollX + bgW
      while (nx < LOGICAL_WIDTH) {
        ctx.drawImage(imgs.bg, nx, 0, bgW, LOGICAL_HEIGHT)
        nx += bgW
      }
    } else {
      ctx.fillStyle = "#70c5ce"
      ctx.fillRect(0, 0, LOGICAL_WIDTH, LOGICAL_HEIGHT)
    }

    // 어둠 오버레이
    if (s.currentBgDarkness > 0) {
      ctx.fillStyle = `rgba(0,0,0,${s.currentBgDarkness})`
      ctx.fillRect(0, 0, LOGICAL_WIDTH, LOGICAL_HEIGHT)
    }

    // 플레이어
    if (imgs && imgs.fish.complete && imgs.fish.naturalWidth !== 0) {
      ctx.drawImage(imgs.fish, PLAYER_X, s.playerY, PLAYER_WIDTH, PLAYER_HEIGHT)
    } else {
      ctx.fillStyle = "#fce502"
      ctx.fillRect(PLAYER_X, s.playerY, PLAYER_WIDTH, PLAYER_HEIGHT)
    }

    // 쓰레기
    s.trashList.forEach((t) => {
      const img = imgs?.trash[t.type]
      if (img && img.complete && img.naturalWidth !== 0) {
        ctx.drawImage(img, t.x, t.y, TRASH_WIDTH, TRASH_HEIGHT)
      } else {
        const colors = ["#73bf2e", "#e67e22", "#e74c3c"]
        ctx.fillStyle = colors[t.type % colors.length]
        ctx.fillRect(t.x, t.y, TRASH_WIDTH, TRASH_HEIGHT)
      }
    })

    // 점수
    ctx.save()
    ctx.fillStyle = "#fff"
    ctx.font = "bold 80px Arial"
    ctx.textAlign = "center"
    ctx.strokeStyle = "#000"
    ctx.lineWidth = 6
    ctx.strokeText(String(s.score), LOGICAL_WIDTH / 2, 100)
    ctx.shadowColor = "rgba(0,0,0,0.5)"
    ctx.shadowBlur = 15
    ctx.shadowOffsetX = 5
    ctx.shadowOffsetY = 5
    ctx.fillText(String(s.score), LOGICAL_WIDTH / 2, 100)
    ctx.restore()

    // 게임오버 오버레이
    if (s.isGameOver) {
      ctx.fillStyle = "rgba(0,0,0,0.7)"
      ctx.fillRect(0, 0, LOGICAL_WIDTH, LOGICAL_HEIGHT)
      ctx.save()
      ctx.textAlign = "center"
      ctx.fillStyle = "#fff"
      ctx.font = "bold 100px Arial"
      ctx.shadowColor = "#f00"
      ctx.shadowBlur = 20
      ctx.fillText("게임 오버", LOGICAL_WIDTH / 2, LOGICAL_HEIGHT / 2 - 50)
      ctx.font = "bold 60px Arial"
      ctx.shadowBlur = 10
      ctx.fillText(`점수: ${s.score}`, LOGICAL_WIDTH / 2, LOGICAL_HEIGHT / 2 + 50)
      ctx.font = "40px Arial"
      ctx.shadowBlur = 0
      ctx.fillText("클릭하여 다시 시작", LOGICAL_WIDTH / 2, LOGICAL_HEIGHT / 2 + 150)
      ctx.restore()
    }
  }, [])

  // ── 게임 루프 ─────────────────────────────────────────
  const gameLoop = useCallback((timestamp: number) => {
    const s = stateRef.current
    if (s.isGameOver) return

    // 물리
    s.playerVelocity += GRAVITY
    s.playerY += s.playerVelocity

    if (s.playerY + PLAYER_HEIGHT > LOGICAL_HEIGHT || s.playerY < 0) {
      s.playerY = Math.max(0, Math.min(LOGICAL_HEIGHT - PLAYER_HEIGHT, s.playerY))
      s.isGameOver = true
      setPhase("over")
      setHighScore((prev) => Math.max(prev, s.score))
      draw()
      return
    }

    const speed = Math.min(MAX_SCROLL_SPEED, SCROLL_SPEED_BASE + Math.floor(s.score / 50) * SCROLL_SPEED_INCREMENT)

    // 배경 스크롤
    const imgs = imagesRef.current
    s.bgScrollX -= speed
    const bgW = imgs && imgs.bg.complete && imgs.bg.naturalWidth !== 0
      ? imgs.bg.naturalWidth * (LOGICAL_HEIGHT / imgs.bg.naturalHeight)
      : LOGICAL_WIDTH
    if (s.bgScrollX <= -bgW) s.bgScrollX = 0

    // 스폰
    const spawnInterval = Math.max(SPAWN_INTERVAL_MIN, SPAWN_INTERVAL_BASE - Math.floor(s.score / 50) * SPAWN_REDUCTION)
    if (timestamp - s.lastSpawnTime > spawnInterval) {
      s.trashList.push({
        x: LOGICAL_WIDTH + Math.random() * 500,
        y: -(Math.random() * 500 + TRASH_HEIGHT),
        fallSpeed: Math.random() * (TRASH_FALL_SPEED_MAX - TRASH_FALL_SPEED_MIN) + TRASH_FALL_SPEED_MIN,
        type: Math.floor(Math.random() * IMG_TRASH.length),
        passed: false,
      })
      s.lastSpawnTime = timestamp
    }

    // 쓰레기 업데이트
    for (let i = s.trashList.length - 1; i >= 0; i--) {
      const t = s.trashList[i]
      t.x -= speed
      t.y += t.fallSpeed

      if (!t.passed && (t.x + TRASH_WIDTH < PLAYER_X || t.y > LOGICAL_HEIGHT)) {
        s.score++
        t.passed = true
        setDisplayScore(s.score)
      }

      // 충돌
      if (
        PLAYER_X + HITBOX_PADDING < t.x + TRASH_WIDTH - HITBOX_PADDING &&
        PLAYER_X + PLAYER_WIDTH - HITBOX_PADDING > t.x + HITBOX_PADDING &&
        s.playerY + HITBOX_PADDING < t.y + TRASH_HEIGHT - HITBOX_PADDING &&
        s.playerY + PLAYER_HEIGHT - HITBOX_PADDING > t.y + HITBOX_PADDING
      ) {
        s.isGameOver = true
        setPhase("over")
        setHighScore((prev) => Math.max(prev, s.score))
        draw()
        return
      }

      if (t.x + TRASH_WIDTH < 0 || t.y > LOGICAL_HEIGHT) {
        s.trashList.splice(i, 1)
      }
    }

    // 어둠
    const diffLevel = Math.floor(s.score / 50)
    const targetDarkness = diffLevel % 2 === 1 ? 0.4 : 0
    const step = 0.005
    if (s.currentBgDarkness < targetDarkness) s.currentBgDarkness = Math.min(targetDarkness, s.currentBgDarkness + step)
    else if (s.currentBgDarkness > targetDarkness) s.currentBgDarkness = Math.max(targetDarkness, s.currentBgDarkness - step)

    draw()
    rafRef.current = requestAnimationFrame(gameLoop)
  }, [draw])

  // ── 게임 시작 / 리셋 ──────────────────────────────────
  const startGame = useCallback(() => {
    cancelAnimationFrame(rafRef.current)
    const s = makeInitialState()
    stateRef.current = s
    setDisplayScore(0)
    setPhase("playing")
    startedRef.current = true
    rafRef.current = requestAnimationFrame((ts) => {
      stateRef.current.lastSpawnTime = ts
      gameLoop(ts)
    })
  }, [gameLoop])

  // ── 입력 ─────────────────────────────────────────────
  const handleInput = useCallback(() => {
    const s = stateRef.current
    if (phase === "over" || (phase === "idle" && startedRef.current)) {
      startGame()
    } else if (phase === "playing") {
      s.playerVelocity = JUMP
    } else {
      // idle 첫 시작
      startGame()
    }
  }, [phase, startGame])

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.code === "Space" && !e.repeat) handleInput()
    }
    window.addEventListener("keydown", onKey)
    return () => window.removeEventListener("keydown", onKey)
  }, [handleInput])

  // ── 언마운트 정리 ─────────────────────────────────────
  useEffect(() => {
    return () => cancelAnimationFrame(rafRef.current)
  }, [])

  return (
    <section id="game" className="py-16 md:py-24 bg-gradient-to-b from-[oklch(0.55_0.15_200)] to-[oklch(0.45_0.12_230)]">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-8">
          <h2 className="text-3xl md:text-4xl font-bold text-white mb-4">미니 게임</h2>
          <p className="text-white/80">바다 쓰레기를 피해 물고기를 살려주세요!</p>
        </div>

        <div className="bg-white rounded-2xl overflow-hidden shadow-xl">
          {/* 헤더 */}
          <div className="bg-[oklch(0.97_0.01_220)] p-4 flex justify-between items-center">
            <div className="flex items-center gap-4">
              <span className="font-bold">점수: {displayScore}</span>
              <div className="flex items-center gap-2">
                <Trophy className="w-5 h-5 text-yellow-500" />
                <span className="font-medium text-sm">최고: {highScore}</span>
              </div>
            </div>
            <span className="text-sm text-gray-500">스페이스 / 클릭으로 조작</span>
          </div>

          {/* 캔버스 영역 */}
          <div ref={containerRef} className="relative w-full" style={{ aspectRatio: "16/9" }}>
            <canvas
              ref={canvasRef}
              className="w-full h-full"
              onClick={handleInput}
              style={{ cursor: "pointer", display: "block" }}
            />

            {/* 시작 전 오버레이 */}
            {phase === "idle" && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40">
                <p className="text-white text-lg mb-6 text-center px-4">
                  쓰레기를 피해 물고기를 조종하세요!<br />
                  <span className="text-sm text-white/70">스페이스 또는 클릭으로 위로 이동</span>
                </p>
                <button
                  onClick={startGame}
                  className="bg-white text-[oklch(0.55_0.15_200)] hover:bg-gray-100 font-bold px-8 py-3 rounded-lg text-lg"
                >
                  게임 시작
                </button>
              </div>
            )}
          </div>

          <div className="p-4 bg-gray-50 text-center text-sm text-gray-600">
            쓰레기를 피하세요. 오래 살아남을수록 고득점!
          </div>
        </div>
      </div>
    </section>
  )
}